(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["pages-pagerouters-pagerouter5"],{6453:function(r,t,b){"use strict";b.r(t);var e=b("c9f7"),n=b("6d19");for(var o in n)["default"].indexOf(o)<0&&function(r){b.d(t,r,(function(){return n[r]}))}(o);b("9a90");var a=b("828b"),i=Object(a["a"])(n["default"],e["b"],e["c"],!1,null,"63ab5e7a",null,!1,e["a"],void 0);t["default"]=i.exports},"6d19":function(r,t,b){"use strict";b.r(t);var e=b("7cb6"),n=b.n(e);for(var o in e)["default"].indexOf(o)<0&&function(r){b.d(t,r,(function(){return e[r]}))}(o);t["default"]=n.a},"7b66":function(r,t,b){var e=b("9eb2");e.__esModule&&(e=e.default),"string"===typeof e&&(e=[[r.i,e,""]]),e.locals&&(r.exports=e.locals);var n=b("967d").default;n("e43df298",e,!0,{sourceMap:!1,shadowMode:!1})},"7cb6":function(r,t,b){"use strict";b("6a54"),Object.defineProperty(t,"__esModule",{value:!0}),t.default=void 0;t.default={data:function(){return{}},methods:{}}},"9a90":function(r,t,b){"use strict";var e=b("7b66"),n=b.n(e);n.a},"9eb2":function(r,t,b){var e=b("c86c");t=e(!1),t.push([r.i,".note[data-v-63ab5e7a]{padding:15px}",""]),r.exports=t},c9f7:function(r,t,b){"use strict";b.d(t,"b",(function(){return e})),b.d(t,"c",(function(){return n})),b.d(t,"a",(function(){}));var e=function(){var r=this,t=r.$createElement,b=r._self._c||t;return b("v-uni-view",[b("div",{staticClass:"note"},[b("p",{staticStyle:{"font-weight":"bold","margin-bottom":"10px","font-size":"1.2rem"}},[r._v("走近回避型依恋者 如何寻找真爱？")]),b("p",{staticStyle:{"margin-bottom":"10px",color:"#6c6c6c"}},[r._v("2024-04-25 | 中国网心理中国 | 迟毓凯")]),b("p",{staticStyle:{"font-weight":"bold"}},[r._v("回避型依恋者，也需要亲密关系")]),b("br"),r._v(" 不知道你有没有听过这样一段话：你说你喜欢太阳，却在阳光明媚的时候躲进阴凉的地方；你说你喜欢风，却在刮风的时候关上窗户；这就是为什么，我害怕你说喜欢我。这段话描述的就是回避型依恋者在亲密关系中的常态。 "),b("br"),b("br"),r._v(" 回避型依恋者，指的是有这样一些特点的人：有强烈的自我保护意识，在亲近的人面前表现得过于理性和冷漠；内心边界感很强，很少能向他人敞开心扉；对亲密关系保持消极态度，躲避长期的亲密关系。 "),b("br"),b("br"),r._v(" 这或许会让你疑惑：回避型依恋者不需要亲密关系吗？其实不然，即便是对于他们这个群体来说，亲密关系也是人生中非常重要的关系。在心理学家埃里克森提出的人生发展八阶段理论中，发展亲密关系、消除孤独感是人成年早期（18~25岁）主要的发展任务。而心理学家马斯洛的需要层次理论中也提到，人们在满足了基本的生理需求以及安全需求后，就会开始追求亲密与爱。由此可见，与他人建立亲密关系是人的一种重要需求，对回避型依恋者也是如此。 "),b("br"),b("br"),b("p",{staticStyle:{"font-weight":"bold"}},[r._v("回避型依恋的特征")]),b("br"),r._v(" 你是否曾接触过回避型依恋者？是否能通过他们的言行举止把他们识别出来？不妨来看个例子，让你对回避型依恋者的特征有更多了解。小红遇到小明，两个人彼此心生好感，就谈起了恋爱。但是小明却常常在小红想更进一步接近他的时候，选择逃避。有时小红想得到一个拥抱，小明却摇摇头拒绝；有时小红想给小明一个惊喜，但他的反应很平淡，甚至是冷漠，令人扫兴。总之，小明常常会无视小红的情感需求，小红一表现出对他的依赖，小明就会拒绝、愤怒或蔑视。最后，在两个人没有矛盾的情况下，小明直接提了分手，将感情干净利索地斩断，完全消失在小红的生活里。小红感到困惑：我真的谈了一场恋爱吗？ "),b("br"),b("br"),r._v(" 是的，小红也是谈了场恋爱，不过是和回避型依恋者谈了一场恋爱。从这个案例中可以看出，小明是一个典型的回避型依恋者。这类人在亲密关系中往往可能表现出以下特征： "),b("br"),b("br"),r._v(" 远离亲密关系：他们倾向于保持一定的距离，不愿意投入太多感情或时间，避免与伴侣建立过于亲密的联系。例如，伴侣使用“男朋友”“女朋友”“情人”或“情侣”等词语时，他们会感到不舒服。 "),b("br"),b("br"),r._v(" 难以接纳关爱：他们可能会对伴侣的关心和爱意表现冷漠或抗拒。当伴侣试图表达情感、亲近他们时，他们可能会回避或拒绝接受。 "),b("br"),b("br"),r._v(" 独立性强：他们通常更加注重个人的独立自主。他们可能更喜欢独自完成任务，而不愿意依赖他人或与他人合作。如果是女生，她们会更难接受“男强女弱”的恋爱关系，更不会因自己的性别和个性特点，就心安理得地接受对方照顾。 封闭情感：他们倾向于不表达自己的情感或需求。他们可能会控制自己的情感表达，不愿意展示自己的脆弱面或需要依赖他人的一面。同样，当伴侣分享脆弱的感受时，也不知道如何回应。 冲突回避：他们可能会避免与伴侣产生冲突或争吵，宁愿选择回避或妥协来维持关系的稳定。 如果爱情中遇到这样的人，那么大致可以确定，你是在和一个回避型依恋者谈恋爱。 "),b("br"),b("br"),b("p",{staticStyle:{"font-weight":"bold"}},[r._v("回避型依恋的形成")]),b("br"),r._v(" 究竟是什么导致了回避型依恋者形成这样的人格呢？这需要从一个经典的心理学研究谈起。 "),b("br"),b("br"),r._v(" 回看成人依恋理论起源，20世纪60年代，英国心理学家鲍尔比首次提出了“依恋”的概念。“依恋”这个词，最初是用来解释主要的养育者，当然通常是母亲了，与婴儿之间的一种情感联系、社会性联结，这也是婴儿情感社会化的重要参考标志之一。1978年，安斯沃斯等研究者通过著名的陌生情境实验，发现婴儿对母亲依恋的表现并非完全相同。根据这些不同表现，研究者将婴儿的依恋类型划分为三种———安全型、回避型、反抗型（焦虑—矛盾型）。 "),b("br"),b("br"),r._v(" 其中，安全型依恋为良好、积极的依恋；而回避型和反抗型依恋属于不安全型依恋，是消极、不良的依恋。影响依恋的安全性有以下四种因素：一是建立亲密关系的机会；二是养育质量；三是婴儿的特征；四是婴儿及其父母生活的家庭环境。形成回避型依恋的婴儿，很可能是因为他们没有机会与养育者建立情感联结，养育者更换频繁或将他们抛弃；他们通常接受到过多刺激和干扰性的照料，很少受到养育者温柔细心的照料和身体接触；他们有着情绪易激惹、难教养的特点，使养育者变得焦虑，从而形成双方之间的“不和谐关系”；他们出生在失业、离婚、贫困等家庭，父母的养育敏感性减弱，损害了婴儿的安全性。在婴儿期形成的回避型依恋，再加上之后缺乏亲密关系的生长环境，人就会长期保持自己的回避型依恋人格，而很难从不安全依恋中复原。 "),b("br"),b("br"),r._v(" 所以，一个人回避型依恋人格的形成，往往是由于个体在年幼时期没有得到养育者恰当的照料，自己的需求没能得到适宜的回应而造成的。当个体成年以后，亲密关系的建立对象从养育者转移到了恋人，他们在年幼时期没有得到的爱与安全感需要从恋人那里得到满足。如果恋人能够满足他们的需求，他们才会建立起安全感并接纳亲密关系，这样恋爱关系也才能持久。 "),b("br"),b("br"),b("p",{staticStyle:{"font-weight":"bold"}},[r._v("回避型依恋者的自我改变")]),b("br"),r._v(" 在互联网上，回避型依恋是一个比较热门的话题，许多网友也自称是一个回避型依恋类型的人，对自己在爱情中种种表现不满意，但对于如何改变并成为一个安全型依恋者感到困惑。这里将提供一些方法，帮助你改变自己。 "),b("br"),b("br"),r._v(" 1、明确自己需求。就像前文提到的，人人都需要亲密关系。回避型依恋者之所以看起来对亲密关系较为回避，其重要原因是在童年早期的成长过程中自己的需求并未得到恰当的回应，所以习惯压抑或独自解决问题。这也导致回避型依恋的人对自己的需求并不清晰，甚至认为自己不存在对亲密关系的需求。所以改变的第一步就是要认识到对亲密关系的需求是自然存在的，然后有意识地去觉察自己的需求，明确需求。 "),b("br"),b("br"),r._v(" 2、练习自我同情。回避型依恋者总会有很多消极的自我对话。你可能会觉得自己不可爱，或者你不值得拥有健康、充满爱的关系。你最终可能会把这种消极情绪投射到你的伴侣身上，假设他们也这样认为。从现在开始，你可以有意识地去注意自己的优势和闪光点，即使是一些很小的事情。然后每天为自己做一件小小的“善举”，比如下班后去你最喜欢的海滩或公园。 "),b("br"),b("br"),r._v(" 3、学会情感表达。回避型依恋者在亲密关系中不愿意去表达自己的情感和想法，不愿意向对方敞开内心。而让对方理解你的前提就是要尝试着去表达，与伴侣分享自己的感受和需要。你可以尝试着使用以“我”为中心的语言表达自己的需求和感受，例如多说“我觉得”和“我想要”。感觉被爱时，也要诚恳地表达出自己对伴侣的爱，例如，“我很喜欢跟你在一起的感觉”。 "),b("br"),b("br"),r._v(" 4、理解对方感受。在与伴侣交流时，尽量放慢节奏，专注于倾听对方的感受和需求。当对方表达负面情绪时，你可能感觉浑身不舒服，想要反击，想要完全否认对方，或者想要逃跑。但这不是好的处理方式。你可以通过重复对方所说的内容，来表达你在倾听他，你可以理解他。又或者，当你无法理解对方为什么总想亲近你时，你可以试着去以“假如我这样做，是为了什么”的思路去理解对方。 "),b("br"),b("br"),r._v(" 通过这些方法，回避型依恋者在爱情中多练习就会发现，你可以摆脱自己的回避，勇敢地享受爱与被爱的感觉。 "),b("br"),b("br"),b("p",{staticStyle:{"font-weight":"bold"}},[r._v("如何与回避型依恋者谈恋爱")]),b("br"),r._v(" 谈一场恋爱，彼此各方面条件都合适，但发现对方是渴望又害怕的回避型依恋者，我们还要继续吗？ "),b("br"),b("br"),r._v(" 尽管是否继续恋爱关系是个人的选择，但在这里我们还是想提供一些建议，帮助想要跟回避型依恋者建立并维持积极的恋爱关系的人获得幸福。 "),b("br"),b("br"),r._v(" 理解回避型依恋的特点：了解回避型依恋者的典型特点，并意识到这些特点影响了他们在恋爱关系中的行为。回避型依恋的人可能需要更多的空间和独立性，他们可能选择回避亲密性或逃避情感。当这些行为发生的时候，可以向他表达适度的理解——我能理解你的感受和行为。 "),b("br"),b("br"),r._v(" 建立安全感：回避型依恋的人在恋爱中格外需要建立安全感。你可以和他通过建立信任、尊重的关系来满足他对安全感的需要。避免过度追求或制造过多的压力，给予他们足够的空间和时间来处理内心的需求。 "),b("br"),b("br"),r._v(" 鼓励开放沟通：回避型依恋的人可能不擅长表达自己的情感和需求。为了建立更好的恋爱关系，你可以鼓励他开放地表达内心感受，并用温暖和支持的态度倾听。同时，你也可以给予他更多耐心，让他有足够的时间来适应和回应你。 "),b("br"),b("br"),b("p",{staticStyle:{"font-weight":"bold"}},[r._v("回避型依恋者，如何寻找真爱")]),b("br"),r._v(" 因为回避型依恋者在两性关系中表现的一些特点，如回避情感、不喜欢身体接触等，可能会引起对方的不满，同时自己对此可能也不满意。那么，回避型依恋者就不适合谈恋爱了吗？ "),b("br"),b("br"),r._v(" 当然不是。一般来说，依恋关系类型只是心理学家对人类情感关系联结的一种类型划分，读者不必紧张或担心。其实，无论是哪种依恋类型，都没有绝对的好与坏。我们要做的是学会自我觉察，要对自己进行深入了解，清楚自己的价值观、兴趣爱好、目标和需求，这样才能明确地知道自己想要的伴侣类型和关系。在寻找真爱的过程中，保持开放心态是很重要的。尽量不要给自己设限或过度理想化，给予人们一些时间去展现他们真实的自我。有时候，真爱可能出现在你最意想不到的时候。 "),b("br"),b("br"),r._v(" 这里尤其给大家普及一个小知识，心理学研究发现，回避型依恋的男生和焦虑型依恋的女生往往是天造地设的一对好伴侣。为什么呢？原因也很简单，这两种依恋风格在很多方面表现迥异，却恰好相互成就，能相互强化彼此的自我认知和爱情观念。焦虑型依恋的女性在恋爱中常常表现得主动，总是会关注情感的互动，而这恰恰能补足回避型依恋男的短板，不会使两人在感情初期感到尴尬；而回避型依恋男想爱又怕深爱的特性会在爱情中表现得忽冷忽热，有些让人琢磨不透，这却又往往让焦虑型依恋女欲罢不能。因此，依恋风格的相互弥补让他们成为适合对方的伴侣。 "),b("br"),b("br"),r._v(" 最后，对任何人来说，没有最好的爱人，只有最适合你的伴侣。回避型依恋不是问题，只要不放弃爱、妥善经营自己的亲密关系，相信你总能在爱中获得幸福和满足。 "),b("br"),b("br"),b("p",{staticStyle:{color:"#6c6c6c"}},[r._v("（迟毓凯/华南师范大学心理学院）")])])])},n=[]}}]);